const PREFIX: Record<SubjectId, string> = {
  biology: "bio",
  biochemistry: "bc",
  "general-chemistry": "gc",
  "organic-chemistry": "oc",
  physics: "ph",
  psychology: "psy",
  sociology: "soc",
};

export const rapidRecallQuestions: Question[] = Object.entries(FACTS).flatMap(
  ([subject, facts]) =>
    facts.flatMap((fact, index) => {
      const [topicId, subtopicId, stem, correctA, correctB, foilA, foilB, explanation] = fact;
      const completions: Array<[string, boolean]> = [
        [correctA, true],
        [foilA, false],
        [correctB, true],
        [foilB, false],
      ];
      return completions.map(([completion, answer], variant) => ({
        id: `rr-${PREFIX[subject as SubjectId]}-${String(index + 1).padStart(2, "0")}-${variant + 1}`,
        subject: subject as SubjectId,
        topicId,
        subtopicId,
        statement: `${stem} ${completion}.`,
        answer,
        explanation,
        difficulty: ((index % 3) + 1) as 1 | 2 | 3,
      }));
    }),
);
